--
-- Table structure for table `violations`
--

CREATE TABLE `violations` (
  `Violation_ID` int(11) NOT NULL,
  `UID` int(11) NOT NULL COMMENT 'Student UID (foreign key)',
  `Student_Number` varchar(20) NOT NULL,
  `Student_Name` varchar(101) NOT NULL COMMENT 'Format: LastName, FirstName M.I',
  `Reported_By_UID` int(11) DEFAULT NULL COMMENT 'UID of person who reported',
  `Reported_By` varchar(100) DEFAULT NULL COMMENT 'Name of who reported',
  `Violation_Type` varchar(50) NOT NULL,
  `Violation_Date` date NOT NULL,
  `Compliance_Deadline` date NOT NULL,
  `Action_Needed` varchar(100) DEFAULT NULL COMMENT 'e.g., Warning, Suspension, Counseling, Community Service',
  `Severity_Level` enum('Minor','Major') DEFAULT 'Minor',
  `Notes` longtext DEFAULT NULL,
  `Created_At` datetime DEFAULT current_timestamp(),
  `Updated_At` datetime DEFAULT NULL ON UPDATE current_timestamp(),
  `year` varchar(20) DEFAULT NULL,
  `section` varchar(20) DEFAULT NULL,
  `Status` enum('Pending','Under Review','Completed','Overdue') DEFAULT 'Pending',
  `Proof_Image` longtext DEFAULT NULL,
  `Proof_FileName` varchar(255) DEFAULT NULL,
  `Proof_Mime` varchar(100) DEFAULT NULL,
  `Proof_Status` enum('Pending','Approved','Rejected') DEFAULT 'Pending',
  `Digital_Signature` longtext DEFAULT NULL,
  `Course` varchar(120) DEFAULT NULL,
  `Proof_History` longtext DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- --------------------------------------------------------

--
-- Table structure for table `violation_archive`
--

CREATE TABLE `violation_archive` (
  `Archive_ID` int(11) NOT NULL,
  `Violation_ID` int(11) DEFAULT NULL COMMENT 'Reference to violation record',
  `Archive_Type` varchar(50) NOT NULL COMMENT 'e.g., Violation, Record, etc.',
  `Name` varchar(101) NOT NULL COMMENT 'Student name or related name',
  `Details` text DEFAULT NULL COMMENT 'Details about what was archived',
  `Archived_Date` date NOT NULL,
  `Days_Left` int(11) DEFAULT NULL COMMENT 'Days left in retention period',
  `Created_At` datetime DEFAULT current_timestamp(),
  `Updated_At` datetime DEFAULT NULL ON UPDATE current_timestamp(),
  `Digital_Signature` longtext DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

