--
-- Table structure for table `violation_backup`
--

CREATE TABLE `violation_backup` (
  `Backup_ID` int(11) NOT NULL,
  `Backup_Name` varchar(255) NOT NULL COMMENT 'e.g., system_backup_full_2026-01-31',
  `Date_Created` datetime NOT NULL,
  `Size` varchar(50) DEFAULT NULL COMMENT 'e.g., 340 MB, 1.5 GB',
  `Type` varchar(50) DEFAULT NULL COMMENT 'e.g., Full System, Incremental',
  `File_Path` varchar(255) DEFAULT NULL COMMENT 'Path to backup file',
  `Created_By_UID` int(11) DEFAULT NULL COMMENT 'FK to users - who created the backup',
  `Created_At` datetime DEFAULT current_timestamp(),
  `Updated_At` datetime DEFAULT NULL ON UPDATE current_timestamp(),
  `Is_Deleted` tinyint(1) DEFAULT 0,
  `Deleted_At` datetime DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

